const FAQS=[{q:"What is an annuity?",a:"An annuity is a financial contract or stream of equal payments made over time, often used for retirement income."},{q:"What is the difference between ordinary annuity and annuity due?",a:"An ordinary annuity pays at the end of each period, while an annuity due pays at the beginning."},{q:"How do you calculate annuity payments?",a:"Payments are calculated from present value, interest rate, and number of periods using an annuity payout formula."},{q:"What is a fixed vs variable annuity?",a:"A fixed annuity has predictable credited interest or payments. A variable annuity can fluctuate with market investments."},{q:"Are annuities a good investment?",a:"They can provide guaranteed income but may have fees, surrender periods, and complexity, so compare carefully."}];
const money=(v:number,d=0)=>formatCurrencyValue(v,{maximumFractionDigits:d});
const payment=(pv:number,rate:number,years:number,due=false)=>{const r=rate/100/12,n=years*12;if(r===0)return pv/n;const p=pv*r/(1-Math.pow(1+r,-n));return due?p/(1+r):p;};
const future=(pmt:number,rate:number,years:number,due=false)=>{const r=rate/100/12,n=years*12;if(r===0)return pmt*n;const fv=pmt*((Math.pow(1+r,n)-1)/r);return due?fv*(1+r):fv;};
export default function AnnuityCalculator(){useCurrencyVersion();const[pv,setPv]=useState(100000),[pmt,setPmt]=useState(600),[rate,setRate]=useState(5),[years,setYears]=useState(20),[type,setType]=useState("ordinary");const due=type==="due";const calcPayment=payment(pv,rate,years,due);const calcFuture=future(pmt,rate,years,due);const schedule=Array.from({length:Math.min(years*12,60)},(_,i)=>{const period=i+1;return{period,payment:pmt,future:future(pmt,rate,period/12,due)}});const rows=[3,4,5,6,7].map(r=>({r,y10:payment(100000,r,10),y20:payment(100000,r,20),y30:payment(100000,r,30),paid:payment(100000,r,20)*240}));const inputClass="w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";return <><SEOHead title="Free Annuity Calculator Online - Calculate Annuity Payments and Value Instantly | CalcHive" description="Free online annuity calculator. Calculate annuity present value, future value and periodic payments for any rate and term instantly. 100% free, no signup required." canonical="/annuity-calculator" keywords="free annuity calculator, annuity payment calculator free online, calculate annuity value free, retirement annuity calculator free, annuity payout calculator free" category="Financial Calculators" breadcrumbName="Free Annuity Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS}/><main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Annuity Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate annuity payment, present value, and future value for ordinary annuities or annuities due.</p></div><AdPlaceholder size="banner" className="mb-8"/><section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Present value</label><input type="number" value={pv} onChange={e=>setPv(Number(e.target.value))} className={inputClass}/></div><div><label className="text-sm font-semibold text-foreground block mb-2">Payment amount</label><input type="number" value={pmt} onChange={e=>setPmt(Number(e.target.value))} className={inputClass}/></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={e=>setRate(Number(e.target.value))} className={inputClass}/></div><div><label className="text-sm font-semibold text-foreground block mb-2">Number of years</label><input type="number" value={years} onChange={e=>setYears(Number(e.target.value))} className={inputClass}/></div><div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Annuity type</label><select value={type} onChange={e=>setType(e.target.value)} className={inputClass}><option value="ordinary">Ordinary annuity</option><option value="due">Annuity due</option></select></div></div><motion.div key={`${pv}-${pmt}-${rate}-${years}-${type}`} initial={{opacity:.7,y:4}} animate={{opacity:1,y:0}}><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Periodic Payment From Present Value</p><p className="text-5xl sm:text-6xl font-black text-white" data-testid="result-annuity">{money(calcPayment)}</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Future value of payments</p><p className="text-lg font-extrabold text-foreground">{money(calcFuture)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total payments</p><p className="text-lg font-extrabold text-foreground">{money(pmt*years*12)}</p></div></div></motion.div></section><ShareButton/><section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Annuity Payments and Value for Free</h2><p className="text-muted-foreground leading-relaxed">This annuity payment calculator free online uses monthly payment formulas for ordinary annuities and annuities due.</p><h2 className="text-2xl font-bold text-foreground">Ordinary Annuity vs Annuity Due Explained</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Annuity Payment on $100,000 at Different Rates and Terms</caption><thead className="bg-muted/60"><tr>{["Interest Rate","10 Years Monthly","20 Years Monthly","30 Years Monthly","Total Paid (20yr)"].map(h=><th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map(r=><tr key={r.r}><td className="py-2.5 px-3 font-semibold">{r.r}%</td><td className="py-2.5 px-3">{money(r.y10)}</td><td className="py-2.5 px-3">{money(r.y20)}</td><td className="py-2.5 px-3">{money(r.y30)}</td><td className="py-2.5 px-3">{money(r.paid)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Retirement Annuity Calculator for Everyone</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Payment Schedule</caption><thead className="bg-muted/60"><tr>{["Period","Payment","Future Value"].map(h=><th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{schedule.map(r=><tr key={r.period}><td className="py-2.5 px-3">{r.period}</td><td className="py-2.5 px-3">{money(r.payment)}</td><td className="py-2.5 px-3">{money(r.future)}</td></tr>)}</tbody></table></div></section><section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map(f=><FAQItem key={f.q} q={f.q} a={f.a}/>)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8"/><RelatedTools exclude="/annuity-calculator" headingLevel="h3"/></main></>;}


